#include <bits/stdc++.h>
using namespace std;

const int N=2e4+10;

int n,m;
long long ans=1e18,sum;

inline long long cal(int r,int h,int len){
    int s1=len*(len-1)/2,s2=s1*(2*len-1)/3,s3=s1*s1;
    return -s3+1LL*(2*r+h)*s2-1LL*(2*r*h+r*r)*s1+1LL*len*r*r*h;
}

void dfs(int x,int lr,int lh,int res){
	//printf("%d %d %d\n",x,lr,lh);
    if(sum>=ans || lr<=x || lh<=x || cal(lr-1,lh-1,x)<res || cal(x,x,x)>res)
        return;
    if(!x){
    	if(res==0)
        	ans=sum;
        return;
    }
    for(int r=x;r<lr && cal(x-1,x-1,x-1)+r*r*x<=res;r++)
        for(int h=x;h<lh && cal(x-1,x-1,x-1)+r*r*h<=res;h++){
            if(h*r*r<res-cal(r-1,h-1,x-1))
                continue;
            sum+=2*r*h;
            if(x==m)
                sum+=r*r;
            dfs(x-1,r,h,res-r*r*h);
            sum-=2*r*h;
            if(x==m)
                sum-=r*r;
        }
}

int main(){
    //printf("%lld\n",cal(4,3,2));
    scanf("%d%d",&n,&m);
    dfs(m,sqrt(n)+1,n+1,n);
    if(ans==1e18)
        printf("0");
    else
        printf("%lld",ans);
    return 0;
}
